FILES = {'backend/app/repositories/user_repository.py': 'from __future__ import annotations\n\nfrom sqlalchemy import select\nfrom sqlalchemy.orm import Session\n\nfrom app.models.user import User\n\n\ndef normalize_username(username: str) -> str:\n    """Normalize usernames before storing or querying."""\n\n    return username.strip().lower()\n\n\ndef normalize_email(email: str | None) -> str | None:\n    """Normalize email address before storing or querying."""\n\n    if email is None:\n        return None\n\n    normalized = email.strip().lower()\n\n    if not normalized:\n        return None\n\n    return normalized\n\n\ndef get_user_by_id(db: Session, user_id: int) -> User | None:\n    """Return user by primary key."""\n\n    statement = select(User).where(User.id == user_id)\n\n    return db.execute(statement).scalar_one_or_none()\n\n\ndef get_user_by_username(\n    db: Session,\n    username: str,\n    business_id: int | None = None,\n) -> User | None:\n    """Return user by normalized username and business scope."""\n\n    normalized_username = normalize_username(username)\n\n    statement = select(User).where(User.username == normalized_username)\n\n    if business_id is None:\n        statement = statement.where(User.business_id.is_(None))\n    else:\n        statement = statement.where(User.business_id == business_id)\n\n    return db.execute(statement).scalar_one_or_none()\n\n\ndef is_username_taken(\n    db: Session,\n    username: str,\n    business_id: int | None = None,\n) -> bool:\n    """Return whether the username already exists in the business scope."""\n\n    return get_user_by_username(\n        db=db,\n        username=username,\n        business_id=business_id,\n    ) is not None\n\n\ndef add_user(db: Session, user: User) -> User:\n    """Add user to session and flush it."""\n\n    db.add(user)\n    db.flush()\n    db.refresh(user)\n\n    return user\n\n\ndef update_last_login_at(db: Session, user: User) -> User:\n    """Flush last_login_at changes for a user."""\n\n    db.add(user)\n    db.flush()\n    db.refresh(user)\n\n    return user\n', 'backend/app/services/auth_service.py': 'from __future__ import annotations\n\nfrom dataclasses import dataclass\nfrom datetime import datetime, timezone\n\nfrom sqlalchemy.orm import Session\n\nfrom app.core.config import settings\nfrom app.core.roles import is_valid_role\nfrom app.core.security import (\n    hash_password,\n    validate_password_strength,\n    verify_password,\n)\nfrom app.core.tokens import create_access_token\nfrom app.models.user import User\nfrom app.repositories.user_repository import (\n    add_user,\n    get_user_by_username,\n    is_username_taken,\n    normalize_email,\n    normalize_username,\n    update_last_login_at,\n)\n\n\nclass AuthServiceError(ValueError):\n    """Base error for auth service failures."""\n\n\nclass DuplicateUsernameError(AuthServiceError):\n    """Raised when username is already used."""\n\n\nclass InvalidCredentialsError(AuthServiceError):\n    """Raised when username or password is wrong."""\n\n\nclass InactiveUserError(AuthServiceError):\n    """Raised when user exists but is inactive."""\n\n\nclass InvalidRoleError(AuthServiceError):\n    """Raised when role is not supported."""\n\n\nclass WeakPasswordError(AuthServiceError):\n    """Raised when password policy validation fails."""\n\n    def __init__(self, errors: list[str]) -> None:\n        self.errors = errors\n        super().__init__(" ".join(errors))\n\n\n@dataclass(frozen=True)\nclass LoginToken:\n    """Login token response generated by auth service."""\n\n    access_token: str\n    token_type: str\n    expires_in_minutes: int\n\n\ndef get_utc_now() -> datetime:\n    """Return current UTC datetime."""\n\n    return datetime.now(timezone.utc)\n\n\ndef create_user_with_password(\n    db: Session,\n    *,\n    full_name: str,\n    username: str,\n    password: str,\n    role: str,\n    business_id: int | None = None,\n    email: str | None = None,\n    theme_preference: str | None = None,\n    is_active: bool = True,\n) -> User:\n    """Create a user after validating role, username and password policy."""\n\n    normalized_username = normalize_username(username)\n    normalized_email = normalize_email(email)\n\n    if not normalized_username:\n        raise AuthServiceError("Kullanıcı adı boş olamaz.")\n\n    if not full_name.strip():\n        raise AuthServiceError("Ad soyad boş olamaz.")\n\n    if not is_valid_role(role):\n        raise InvalidRoleError("Geçersiz kullanıcı rolü.")\n\n    password_errors = validate_password_strength(password)\n\n    if password_errors:\n        raise WeakPasswordError(password_errors)\n\n    if is_username_taken(\n        db=db,\n        username=normalized_username,\n        business_id=business_id,\n    ):\n        raise DuplicateUsernameError("Bu kullanıcı adı zaten kullanılıyor.")\n\n    now = get_utc_now()\n\n    user = User(\n        business_id=business_id,\n        full_name=full_name.strip(),\n        email=normalized_email,\n        username=normalized_username,\n        password_hash=hash_password(password),\n        role=role,\n        theme_preference=theme_preference,\n        is_active=is_active,\n        last_login_at=None,\n        created_at=now,\n        updated_at=now,\n    )\n\n    return add_user(db=db, user=user)\n\n\ndef authenticate_user(\n    db: Session,\n    *,\n    username: str,\n    password: str,\n    business_id: int | None = None,\n) -> User:\n    """Authenticate user by username and password."""\n\n    user = get_user_by_username(\n        db=db,\n        username=username,\n        business_id=business_id,\n    )\n\n    if user is None:\n        raise InvalidCredentialsError("Kullanıcı adı veya şifre hatalı.")\n\n    if not user.is_active:\n        raise InactiveUserError("Kullanıcı pasif durumda.")\n\n    if not verify_password(password, user.password_hash):\n        raise InvalidCredentialsError("Kullanıcı adı veya şifre hatalı.")\n\n    user.last_login_at = get_utc_now()\n    user.updated_at = get_utc_now()\n\n    return update_last_login_at(db=db, user=user)\n\n\ndef create_login_token_for_user(user: User) -> LoginToken:\n    """Create access token for an authenticated user."""\n\n    access_token = create_access_token(\n        subject=str(user.id),\n        role=user.role,\n        business_id=user.business_id,\n    )\n\n    return LoginToken(\n        access_token=access_token,\n        token_type="bearer",\n        expires_in_minutes=settings.access_token_expire_minutes,\n    )\n', 'backend/app/commands/check_auth_service.py': 'from __future__ import annotations\n\nimport app.models  # noqa: F401\nfrom app.core.tokens import decode_access_token\nfrom app.db.session import SessionLocal\nfrom app.models.user import User\nfrom app.repositories.user_repository import get_user_by_username\nfrom app.services.auth_service import (\n    authenticate_user,\n    create_login_token_for_user,\n    create_user_with_password,\n)\n\n\nTEST_USERNAME = "missio_auth_test_admin"\nTEST_PASSWORD = "Missio.2026!"\n\n\ndef delete_test_user_if_exists() -> None:\n    """Delete previous test user if it exists."""\n\n    db = SessionLocal()\n\n    try:\n        user = get_user_by_username(\n            db=db,\n            username=TEST_USERNAME,\n            business_id=None,\n        )\n\n        if user is not None:\n            db.delete(user)\n            db.commit()\n    finally:\n        db.close()\n\n\ndef main() -> None:\n    """Run auth service check against the local database."""\n\n    delete_test_user_if_exists()\n\n    db = SessionLocal()\n\n    try:\n        user = create_user_with_password(\n            db=db,\n            full_name="Missio Test Admin",\n            username=TEST_USERNAME,\n            password=TEST_PASSWORD,\n            role="super_admin",\n            business_id=None,\n            email="missio.auth.test@example.com",\n            is_active=True,\n        )\n        db.commit()\n        db.refresh(user)\n\n        if TEST_PASSWORD in user.password_hash:\n            raise RuntimeError("Şifre hash içinde açık görünüyor.")\n\n        authenticated_user = authenticate_user(\n            db=db,\n            username=TEST_USERNAME,\n            password=TEST_PASSWORD,\n            business_id=None,\n        )\n        db.commit()\n        db.refresh(authenticated_user)\n\n        if authenticated_user.last_login_at is None:\n            raise RuntimeError("last_login_at güncellenmedi.")\n\n        login_token = create_login_token_for_user(authenticated_user)\n        payload = decode_access_token(login_token.access_token)\n\n        if payload.subject != str(authenticated_user.id):\n            raise RuntimeError("Token subject bilgisi hatalı.")\n\n        if payload.role != "super_admin":\n            raise RuntimeError("Token rol bilgisi hatalı.")\n\n        if payload.business_id is not None:\n            raise RuntimeError("Super admin token business_id boş olmalı.")\n\n        print("Auth service kullanıcı oluşturma kontrolü başarılı.")\n        print("Auth service kullanıcı doğrulama kontrolü başarılı.")\n        print("Auth service token üretme kontrolü başarılı.")\n    finally:\n        db.close()\n        delete_test_user_if_exists()\n\n    print("Auth service temel kontrolü başarılı.")\n\n\nif __name__ == "__main__":\n    main()\n', 'backend/tests/test_auth_service.py': 'from collections.abc import Generator\n\nimport pytest\nfrom sqlalchemy import create_engine, event\nfrom sqlalchemy.orm import Session, sessionmaker\n\nimport app.models  # noqa: F401\nfrom app.core.tokens import decode_access_token\nfrom app.db.base import Base\nfrom app.models.business import Business\nfrom app.services.auth_service import (\n    DuplicateUsernameError,\n    InactiveUserError,\n    InvalidCredentialsError,\n    WeakPasswordError,\n    authenticate_user,\n    create_login_token_for_user,\n    create_user_with_password,\n)\n\n\n@pytest.fixture()\ndef db_session() -> Generator[Session, None, None]:\n    engine = create_engine(\n        "sqlite:///:memory:",\n        connect_args={"check_same_thread": False},\n    )\n\n    @event.listens_for(engine, "connect")\n    def enable_foreign_keys(dbapi_connection, connection_record) -> None:\n        del connection_record\n        cursor = dbapi_connection.cursor()\n        cursor.execute("PRAGMA foreign_keys=ON")\n        cursor.close()\n\n    TestingSessionLocal = sessionmaker(\n        autocommit=False,\n        autoflush=False,\n        bind=engine,\n    )\n\n    Base.metadata.create_all(bind=engine)\n\n    db = TestingSessionLocal()\n\n    try:\n        yield db\n    finally:\n        db.close()\n        Base.metadata.drop_all(bind=engine)\n        engine.dispose()\n\n\ndef create_business(db: Session) -> Business:\n    business = Business(\n        name="Test İşletme",\n        slug="test-isletme",\n        logo_path=None,\n        owner_name="Test Owner",\n        phone=None,\n        email="owner@example.com",\n        address=None,\n        timezone="Europe/Istanbul",\n        default_theme="dark",\n        is_active=True,\n        created_at=create_user_with_password.__globals__["get_utc_now"](),\n        updated_at=create_user_with_password.__globals__["get_utc_now"](),\n    )\n\n    db.add(business)\n    db.commit()\n    db.refresh(business)\n\n    return business\n\n\ndef test_create_user_with_password_hashes_password(db_session: Session) -> None:\n    user = create_user_with_password(\n        db=db_session,\n        full_name="Test User",\n        username="TestUser",\n        password="Missio.2026!",\n        role="super_admin",\n        business_id=None,\n        email="TEST@EXAMPLE.COM",\n    )\n\n    db_session.commit()\n    db_session.refresh(user)\n\n    assert user.id is not None\n    assert user.username == "testuser"\n    assert user.email == "test@example.com"\n    assert "Missio.2026!" not in user.password_hash\n\n\ndef test_create_user_rejects_weak_password(db_session: Session) -> None:\n    with pytest.raises(WeakPasswordError):\n        create_user_with_password(\n            db=db_session,\n            full_name="Weak User",\n            username="weakuser",\n            password="123",\n            role="staff",\n            business_id=None,\n        )\n\n\ndef test_create_user_rejects_duplicate_username(db_session: Session) -> None:\n    create_user_with_password(\n        db=db_session,\n        full_name="First User",\n        username="sameuser",\n        password="Missio.2026!",\n        role="super_admin",\n        business_id=None,\n    )\n    db_session.commit()\n\n    with pytest.raises(DuplicateUsernameError):\n        create_user_with_password(\n            db=db_session,\n            full_name="Second User",\n            username="sameuser",\n            password="Missio.2026!",\n            role="super_admin",\n            business_id=None,\n        )\n\n\ndef test_authenticate_user_updates_last_login(db_session: Session) -> None:\n    user = create_user_with_password(\n        db=db_session,\n        full_name="Login User",\n        username="loginuser",\n        password="Missio.2026!",\n        role="super_admin",\n        business_id=None,\n    )\n    db_session.commit()\n    db_session.refresh(user)\n\n    authenticated_user = authenticate_user(\n        db=db_session,\n        username="loginuser",\n        password="Missio.2026!",\n        business_id=None,\n    )\n\n    assert authenticated_user.id == user.id\n    assert authenticated_user.last_login_at is not None\n\n\ndef test_authenticate_user_rejects_wrong_password(db_session: Session) -> None:\n    create_user_with_password(\n        db=db_session,\n        full_name="Wrong Password User",\n        username="wrongpassword",\n        password="Missio.2026!",\n        role="super_admin",\n        business_id=None,\n    )\n    db_session.commit()\n\n    with pytest.raises(InvalidCredentialsError):\n        authenticate_user(\n            db=db_session,\n            username="wrongpassword",\n            password="Wrong.2026!",\n            business_id=None,\n        )\n\n\ndef test_authenticate_user_rejects_inactive_user(db_session: Session) -> None:\n    create_user_with_password(\n        db=db_session,\n        full_name="Inactive User",\n        username="inactiveuser",\n        password="Missio.2026!",\n        role="super_admin",\n        business_id=None,\n        is_active=False,\n    )\n    db_session.commit()\n\n    with pytest.raises(InactiveUserError):\n        authenticate_user(\n            db=db_session,\n            username="inactiveuser",\n            password="Missio.2026!",\n            business_id=None,\n        )\n\n\ndef test_create_login_token_for_business_user(db_session: Session) -> None:\n    business = create_business(db_session)\n\n    user = create_user_with_password(\n        db=db_session,\n        full_name="Staff User",\n        username="staffuser",\n        password="Missio.2026!",\n        role="staff",\n        business_id=business.id,\n    )\n    db_session.commit()\n    db_session.refresh(user)\n\n    login_token = create_login_token_for_user(user)\n    payload = decode_access_token(login_token.access_token)\n\n    assert login_token.token_type == "bearer"\n    assert payload.subject == str(user.id)\n    assert payload.role == "staff"\n    assert payload.business_id == business.id\n'}


def write_file(relative_path: str, content: str) -> None:
    target = ROOT_DIR / relative_path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")
    print(f"Yazildi: {target}")


def compile_files() -> None:
    for relative_path in FILES:
        if relative_path.endswith(".py"):
            py_compile.compile(str(ROOT_DIR / relative_path), doraise=True)

    print("Python syntax kontrolu basarili.")


def main() -> None:
    print("Missio ADIM 5C kullanici repository ve auth service temeli olusturuluyor.")
    print("")

    for relative_path, content in FILES.items():
        write_file(relative_path, content)

    compile_files()

    print("")
    print("Tamamlandi.")


if __name__ == "__main__":
    main()
